/// <summary>
/// Abhinav - Hide fields based on parameters
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;
    ret =  next active();

    element.design().controlName(formControlStr(InventJournalBOM,ETGProdEntityJournal)).visible(ETGCanadaParameters::find().SelectJournalForAutoCreation);
    element.design().controlName(formControlStr(InventJournalBOM,ETGSubcontractingBOMJournal)).visible(ETGCanadaParameters::find().EnableAutoCreateBOM);
    element.design().controlName(formControlStr(InventJournalBOM,ETGIsJournalPosted)).visible(ETGCanadaParameters::find().EnableAutoCreateBOM);

    //CS,DLT,SB Subcontracting BOM marking to Sales Order
    InventJournalTable  InventJournalTable, InventJournalTableNew;
    InventJournalTable    = this.cursor();

    boolean     enableSubcontractingBOMMarking = InventJournalName::find(InventJournalTable.JournalNameId).ETGAutoCreateBOMJournal == NoYes::Yes
        && InventJournalName::find(InventJournalTable.JournalNameId).ETGSelectJournalForAutoCreation == NoYes::Yes && ETGCanadaParameters::find().EnableBOMJournalMarking == NoYes::Yes;

    element.design().controlName(formControlStr(InventJournalBOM, InventJournalTable_ETGSalesId)).visible(enableSubcontractingBOMMarking);
    element.design().controlName(formControlStr(InventJournalBOM, InventJournalTable_ETGItemId)).visible(enableSubcontractingBOMMarking);
    //CE,DLT,SB

    return ret;
}
